<template>
  <Transition name="modal">
    <div v-if="show" class="kid-game-modal-overlay" @click="handleOverlayClick">
      <div class="kid-game-modal" :class="[`type-${type}`]" @click.stop>
        <!-- 头部图标/表情 -->
        <div v-if="icon || emoji" class="game-modal-icon">
          {{ emoji }}
        </div>

        <!-- 标题 -->
        <h2 class="game-modal-title">{{ title }}</h2>

        <!-- 副标题/描述 -->
        <p v-if="subtitle" class="game-modal-subtitle">{{ subtitle }}</p>

        <!-- 内容区域 -->
        <div class="game-modal-content">
          <slot>
            <!-- 默认显示统计数据 -->
            <div v-if="stats.length > 0" class="game-modal-stats">
              <div
                v-for="(stat, index) in stats"
                :key="index"
                class="stat-item"
              >
                <span class="stat-label">{{ stat.label }}</span>
                <span class="stat-value">{{ stat.value }}</span>
              </div>
            </div>
          </slot>
        </div>

        <!-- 操作按钮 -->
        <div class="game-modal-actions" :class="[`layout-${actionsLayout}`]">
          <slot name="actions">
            <button
              v-for="(action, index) in actions"
              :key="index"
              :class="[
                'game-modal-action',
                `variant-${action.variant || 'primary'}`,
              ]"
              @click="action.onClick"
            >
              {{ action.text }}
            </button>
          </slot>
        </div>
      </div>
    </div>
  </Transition>
</template>

<script setup lang="ts">
import { onMounted, onUnmounted } from 'vue';

interface Stat {
  label: string;
  value: string | number;
}

interface Action {
  text: string;
  variant?: 'primary' | 'secondary' | 'success' | 'danger';
  onClick: () => void;
}

interface Props {
  show: boolean;
  title: string;
  subtitle?: string;
  type?: 'result' | 'reward' | 'levelup' | 'gameover';
  icon?: string;
  emoji?: string;
  stats?: Stat[];
  actions?: Action[];
  actionsLayout?: 'horizontal' | 'vertical';
  closeOnClickOverlay?: boolean;
}

const props = withDefaults(defineProps<Props>(), {
  type: 'result',
  icon: '',
  stats: () => [],
  actions: () => [],
  actionsLayout: 'vertical',
  closeOnClickOverlay: false,
});

const emit = defineEmits<{
  'update:show': [value: boolean];
  close: [];
}>();

function handleOverlayClick() {
  if (props.closeOnClickOverlay) {
    emit('update:show', false);
    emit('close');
  }
}

// ESC 键关闭（如果有取消按钮则触发第一个取消操作）
function handleEscapeKey(event: KeyboardEvent) {
  if (event.key === 'Escape' || event.keyCode === 27) {
    if (props.actions && props.actions.length > 0) {
      // 执行第一个动作（通常是主要操作）
      props.actions[0].onClick();
    } else {
      emit('update:show', false);
      emit('close');
    }
  }
}

onMounted(() => {
  if (props.show) {
    document.addEventListener('keydown', handleEscapeKey);
  }
});

onUnmounted(() => {
  document.removeEventListener('keydown', handleEscapeKey);
});
</script>

